import{c as r,Q as o,j as a,m as t}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"The Decoder — 2026-05-27","description":"","frontmatter":{"title":"The Decoder — 2026-05-27","date":"2026-05-27T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-27-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-27-the-decoder.md","lastUpdated":1779927176000}'),s={name:"research/ai-news/2026-05/2026-05-27-the-decoder.md"};function i(n,e,l,h,c,d){return o(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="🔓-the-decoder-—-2026-05-27" tabindex="-1">🔓 The Decoder — 2026-05-27 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-27" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-27&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="claude-mythos-reportedly-solves-openai-s-landmark-erdos-problem-with-a-cute-simple-proof" tabindex="-1"><a href="https://the-decoder.com/claude-mythos-reportedly-solves-openais-landmark-erdos-problem-with-a-cute-simple-proof/" target="_blank" rel="noreferrer">Claude Mythos reportedly solves OpenAI&#39;s landmark Erdős problem with a &quot;cute, simple proof&quot;</a> <a class="header-anchor" href="#claude-mythos-reportedly-solves-openai-s-landmark-erdos-problem-with-a-cute-simple-proof" aria-label="Permalink to &quot;[Claude Mythos reportedly solves OpenAI&#39;s landmark Erdős problem with a &quot;cute, simple proof&quot;](https://the-decoder.com/claude-mythos-reportedly-solves-openais-landmark-erdos-problem-with-a-cute-simple-proof/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-26</em></p><p>Shortly after OpenAI disproved Erdős&#39; unit-distance conjecture, Anthropic shows Claude Mythos can solve the problem too - &quot;over the weekend.&quot; Engineer Sholto Douglas says Mythos cracked the 1946 conjecture with a &quot;cute, simple proof,&quot; a sign of &quot;serious overhang&quot; in AI-driven math discoveries.</p><p>The article <a href="https://the-decoder.com/claude-mythos-reportedly-solves-openais-landmark-erdos-problem-with-a-cute-simple-proof/" target="_blank" rel="noreferrer">Claude Mythos reportedly solves OpenAI&#39;s landmark Erdős problem with a &quot;cute, simple proof&quot;</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="china-reportedly-now-requires-top-ai-researchers-to-get-permission-before-leaving-the-country" tabindex="-1"><a href="https://the-decoder.com/china-reportedly-now-requires-top-ai-researchers-to-get-permission-before-leaving-the-country/" target="_blank" rel="noreferrer">China reportedly now requires top AI researchers to get permission before leaving the country</a> <a class="header-anchor" href="#china-reportedly-now-requires-top-ai-researchers-to-get-permission-before-leaving-the-country" aria-label="Permalink to &quot;[China reportedly now requires top AI researchers to get permission before leaving the country](https://the-decoder.com/china-reportedly-now-requires-top-ai-researchers-to-get-permission-before-leaving-the-country/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-26</em></p><p>China is now restricting overseas travel for top AI researchers at private companies like Alibaba and DeepSeek. Those affected need official approval before leaving the country. Beijing fears data leaks, technology theft, and talent poaching and is tightening its grip on the domestic AI industry.</p><p>The article <a href="https://the-decoder.com/china-reportedly-now-requires-top-ai-researchers-to-get-permission-before-leaving-the-country/" target="_blank" rel="noreferrer">China reportedly now requires top AI researchers to get permission before leaving the country</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="google-cloud-coo-says-ai-security-belongs-in-the-boardroom-not-just-the-server-room" tabindex="-1"><a href="https://the-decoder.com/google-cloud-coo-says-ai-security-belongs-in-the-boardroom-not-just-the-server-room/" target="_blank" rel="noreferrer">Google Cloud COO says AI security belongs in the boardroom, not just the server room</a> <a class="header-anchor" href="#google-cloud-coo-says-ai-security-belongs-in-the-boardroom-not-just-the-server-room" aria-label="Permalink to &quot;[Google Cloud COO says AI security belongs in the boardroom, not just the server room](https://the-decoder.com/google-cloud-coo-says-ai-security-belongs-in-the-boardroom-not-just-the-server-room/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-26</em></p><p>Google Cloud COO Francis de Souza is urging companies to build security into their AI strategy from day one.</p><p>The article <a href="https://the-decoder.com/google-cloud-coo-says-ai-security-belongs-in-the-boardroom-not-just-the-server-room/" target="_blank" rel="noreferrer">Google Cloud COO says AI security belongs in the boardroom, not just the server room</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="ai-hallucinated-citations-are-creeping-into-papers-that-shape-clinical-guidelines-researchers-warn" tabindex="-1"><a href="https://the-decoder.com/ai-hallucinated-citations-are-creeping-into-papers-that-shape-clinical-guidelines-researchers-warn/" target="_blank" rel="noreferrer">AI-hallucinated citations are creeping into papers that shape clinical guidelines, researchers warn</a> <a class="header-anchor" href="#ai-hallucinated-citations-are-creeping-into-papers-that-shape-clinical-guidelines-researchers-warn" aria-label="Permalink to &quot;[AI-hallucinated citations are creeping into papers that shape clinical guidelines, researchers warn](https://the-decoder.com/ai-hallucinated-citations-are-creeping-into-papers-that-shape-clinical-guidelines-researchers-warn/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-26</em></p><p>An audit of 2.5 million biomedical papers by Columbia University and other institutions shows that the rate of fabricated references has increased more than twelvefold since 2023. The researchers suspect a link to the widespread use of language models - the fake references match their paper&#39;s topic, follow correct formatting, and are nearly impossible to spot. 98 percent of the affected papers have received no response from their publishers.</p><p>The article <a href="https://the-decoder.com/ai-hallucinated-citations-are-creeping-into-papers-that-shape-clinical-guidelines-researchers-warn/" target="_blank" rel="noreferrer">AI-hallucinated citations are creeping into papers that shape clinical guidelines, researchers warn</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="y-combinator-founder-paul-graham-says-ai-written-founder-emails-feel-like-being-lied-to" tabindex="-1"><a href="https://the-decoder.com/y-combinator-founder-paul-graham-says-ai-written-founder-emails-feel-like-being-lied-to/" target="_blank" rel="noreferrer">Y Combinator founder Paul Graham says AI-written founder emails feel like being lied to</a> <a class="header-anchor" href="#y-combinator-founder-paul-graham-says-ai-written-founder-emails-feel-like-being-lied-to" aria-label="Permalink to &quot;[Y Combinator founder Paul Graham says AI-written founder emails feel like being lied to](https://the-decoder.com/y-combinator-founder-paul-graham-says-ai-written-founder-emails-feel-like-being-lied-to/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-26</em></p><p>Y Combinator founder Paul Graham ignores emails clearly written by AI—they feel &quot;like being lied to,&quot; he says. That&#39;s coming from one of OpenAI&#39;s earliest investors. Studies suggest his reaction is anything but unusual.</p><p>The article <a href="https://the-decoder.com/y-combinator-founder-paul-graham-says-ai-written-founder-emails-feel-like-being-lied-to/" target="_blank" rel="noreferrer">Y Combinator founder Paul Graham says AI-written founder emails feel like being lied to</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const m=r(s,[["render",i]]);export{u as __pageData,m as default};
